// Created: 2026-06-11

// Per-IP fixed-window rate limiter for the public read-only API. In-memory and
// therefore per-serverless-instance: a single instance enforces the window
// exactly; across instances the effective ceiling is N× the limit, which is
// acceptable for an abuse brake on a CDN-fronted free API. The point is real
// enforcement plus the IETF draft RateLimit-* headers agents use for pacing
// (draft-ietf-httpapi-ratelimit-headers).

const WINDOW_SECONDS = 60;
export const RATE_LIMIT = 120; // requests per window per IP per route

type Window = { count: number; resetAt: number };
const windows = new Map<string, Window>();

export type RateLimitResult = {
	limited: boolean;
	remaining: number;
	resetSeconds: number;
};

export function checkRateLimit(req: Request, route: string): RateLimitResult {
	const ip =
		req.headers.get("x-real-ip") ??
		req.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ??
		"unknown";
	const key = `${route}:${ip}`;
	const now = Date.now();

	let win = windows.get(key);
	if (!win || win.resetAt <= now) {
		// Opportunistically drop expired windows so the map doesn't grow unbounded.
		if (windows.size > 10_000) {
			for (const [k, w] of windows) {
				if (w.resetAt <= now) windows.delete(k);
			}
		}
		win = { count: 0, resetAt: now + WINDOW_SECONDS * 1000 };
		windows.set(key, win);
	}

	win.count += 1;
	return {
		limited: win.count > RATE_LIMIT,
		remaining: Math.max(0, RATE_LIMIT - win.count),
		resetSeconds: Math.max(1, Math.ceil((win.resetAt - now) / 1000)),
	};
}

export function rateLimitHeaders(result: RateLimitResult): Record<string, string> {
	return {
		"RateLimit-Policy": `${RATE_LIMIT};w=${WINDOW_SECONDS}`,
		"RateLimit-Limit": String(RATE_LIMIT),
		"RateLimit-Remaining": String(result.remaining),
		"RateLimit-Reset": String(result.resetSeconds),
		// Legacy X- variants for toolchains that predate the IETF draft names.
		"X-RateLimit-Limit": String(RATE_LIMIT),
		"X-RateLimit-Remaining": String(result.remaining),
		"X-RateLimit-Reset": String(result.resetSeconds),
	};
}
